import { readFile } from "node:fs/promises";

import { defineEval } from "niceeval";
import { commandSucceeded } from "niceeval/expect";

// 挖自真实合入 PR ReactTooltip/react-tooltip#1275(不让被测 agent 看到 PR 号/commit)。merge commit
// cd6a0ff20864264de012460f7f5cfacf6c259850 提供隐藏测试的权威 post-fix 内容。Bug:openOnClick 下点击
// anchor 本应打开其 tooltip,但库在 document 级、冒泡阶段监听 click,如果 anchor 自己的 click handler
// 调了 event.stopPropagation(),事件永远到不了委托监听器,tooltip 打不开。真实修复改了委托 click 监听
// 的注册方式(捕获阶段),源码在 src/components/Tooltip/event-delegation.ts 与 use-tooltip-events.tsx。
// 隐藏测试是 interaction-behavior spec 里新增的一个用例(断言 anchor 停止冒泡时点击仍打开 tooltip),
// 断言全在可观察行为上、不 import 任何新符号,base_sha 下必失败(1 failed / 8 passed),打上真实修复后
// 9 全绿——本地 Node 20.9.0 双向验证过。
const fixture = (path: string) => new URL(`../fixtures/react-tooltip/pr-1275/${path}`, import.meta.url);

const REPO_URL = "https://github.com/ReactTooltip/react-tooltip.git";
const BASE_COMMIT = "3b275df3ff43cc532eb2b2b0daf7705aec566ad6";

export default defineEval({
  description:
    "react-tooltip pr-1275: with openOnClick, clicking an anchor whose own click handler calls " +
    "stopPropagation() fails to open the tooltip, because the library listens for clicks at the document level " +
    "during the bubbling phase; clicking the anchor must open the tooltip even when propagation is stopped " +
    "(real react-tooltip issue)",
  // 纯 Node 仓库,yarn classic v1 装依赖、跑单个 jest 文件都在数十秒内完成,用默认超时足够。
  diff: {
    // yarn.lock 在 install 阶段可能被重写(元数据/排序变化,字节级差异,无实际依赖变更)——
    // 这是 install 步骤本身的副作用,不是 agent 的改动。
    ignore: ["coverage", "node_modules", "yarn.lock"],
  },
  async test(t) {
    // 没有单独的 workspace 起始目录——fixture 就是这个 base commit 本身:clone 真实 repo、
    // 退到 base commit、抹掉未来历史(remote/tags/reflog),agent 拿到带真实(截断)git 历史
    // 的 checkout。checkout 必须在 workdir 根——嵌套子目录会被 diff 分类账记成 gitlink,
    // agent 的改动就从证据里消失了。任务说明只通过下面的 t.send() 传给 agent。
    t.progress({ message: "cloning react-tooltip @ base commit" });
    const cloned = await t.sandbox.runShell(
      [
        "set -euo pipefail",
        `git clone -q -o origin --single-branch ${REPO_URL} .rt-clone`,
        "mv .rt-clone/.git .git",
        "rm -rf .rt-clone",
        `git reset -q --hard ${BASE_COMMIT}`,
        "git remote remove origin",
        "git tag -l | xargs -r git tag -d >/dev/null",
        "git reflog expire --expire=now --all",
        "git gc -q --prune=now",
        // 上游同款自检:base commit 之后不应再有任何 commit 可见
        `TS=$(git show -s --format=%ci ${BASE_COMMIT})`,
        'COUNT=$(git log --oneline --since="$TS" | wc -l)',
        '[ "$COUNT" -eq 1 ]',
      ].join("\n"),
    );
    if (cloned.exitCode !== 0) {
      throw new Error(`react-tooltip checkout failed: ${(cloned.stderr || cloned.stdout).trim().slice(-500)}`);
    }

    // No packageManager field pinned, so corepack is unsafe on the sandbox's Node 20.9.0.
    // Install yarn classic v1 explicitly. --ignore-engines covers Node 20.9.0 against
    // devDependencies that declare stricter ranges; --ignore-scripts skips native-module
    // postinstall builds (e.g. an old brotli addon) that are not needed to run Jest.
    t.progress({ message: "installing deps (yarn classic v1)" });
    const installed = await t.sandbox.runShell(
      "npm install -g --prefix /usr/local yarn@1.22.22 && yarn install --ignore-scripts --ignore-engines",
    );
    if (installed.exitCode !== 0) {
      throw new Error(`yarn install failed: ${(installed.stderr || installed.stdout).trim().slice(-500)}`);
    }

    await t
      .send(
        "Your working directory is a checkout of the real react-tooltip repository at the commit where the bug " +
          "below reproduces. Find and fix the bug in the library source.\n\n" +
          "Bug: with the click trigger enabled (`openOnClick`), clicking an anchor element is supposed to open " +
          "its tooltip. The library implements this by listening for click events at the document level. " +
          "Because that delegated listener runs during the event's bubbling phase, if the anchor's own click " +
          "handler calls `event.stopPropagation()`, the click never bubbles up to the document, the library's " +
          "delegated listener never runs, and the tooltip fails to open. The correct behavior is that clicking " +
          "the anchor opens its tooltip even when the anchor stops propagation of the click event. Fix how/when " +
          "the library registers its delegated click handling so that a propagation-stopping anchor still opens " +
          "the tooltip. Fix the library source (under `src/`); do not just add workarounds in test files.\n\n" +
          "Environment notes: no root access is needed. Dependencies are already installed via `npm install -g " +
          "yarn@1.22.22 && yarn install --ignore-scripts --ignore-engines`. Run tests with Jest, e.g. " +
          "`node_modules/.bin/jest src/test/tooltip-interaction-behavior.spec.js`. The event-delegation logic " +
          "lives under `src/components/Tooltip/`. Fix the library source; do not just add workarounds in test " +
          "files.",
      )
      .then((turn) => turn.expectOk());

    const spec = await readFile(fixture("tests/tooltip-interaction-behavior.spec.js"), "utf8");
    const runTests = await readFile(fixture("tests/run-tests.sh"), "utf8");
    await t.sandbox.writeFiles({
      "src/test/tooltip-interaction-behavior.spec.js": spec,
      "tests/run-tests.sh": runTests,
    });

    t.check(await t.sandbox.runCommand("bash", ["tests/run-tests.sh"]), commandSucceeded());
  },
});
